/**
 * Consulta el tipo de visado para una combinación pasaporte→destino
 * Returns: 'free' | 'voa' | 'evisa' | 'required' | null
 */
export function getVisaFromDB(destISO, passportISO) {
  if (!destISO || !passportISO) return null;
  const dest = VISA_DB[destISO];
  if (!dest) return null;
  return dest[passportISO] || null;
}

/**
 * Convierte el tipo a objeto compatible con visaMatrix.js
 */
export function visaTypeToInfo(type, destName) {
  switch(type) {
    case 'free':     return { needed: false, days: 90, eVisa: false, cost: null, info: 'Sin visado requerido.', url: null };
    case 'voa':      return { needed: true,  days: null, eVisa: false, cost: null, info: 'Visado a la llegada disponible en el aeropuerto.', url: null };
    case 'evisa':    return { needed: true,  days: null, eVisa: true, cost: null, info: 'E-Visa disponible online antes de viajar.', url: null };
    case 'required': return { needed: true,  days: null, eVisa: false, cost: null, info: `Visado requerido. Consulta la embajada de ${destName || 'destino'}.`, url: null };
    default:         return null;
  }
}